import React, { useState, useEffect } from 'react';
import './Navbar.css';

const links = [
  { label: 'Trang chủ', href: '#hero' },
  { label: 'Dịch vụ', href: '#services' },
  { label: 'Bảng giá', href: '#pricing' },
  { label: 'Về chúng tôi', href: '#about' },
  { label: 'Đối tác', href: '#partner' },
  { label: 'Tuyển dụng', href: '#recruitment' },
  { label: 'Liên hệ', href: '#contact' },
];

export default function Navbar() {
  const [scrolled, setScrolled] = useState(false);
  const [open, setOpen] = useState(false);

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 60);
    window.addEventListener('scroll', onScroll);
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  return (
    <header className={`navbar${scrolled ? ' navbar--scrolled' : ''}`}>
      <div className="container navbar__inner">
        <a href="#hero" className="navbar__logo">
          <span className="navbar__logo-icon"><img 
        src="blob:https://www.image2url.com/30172c21-df26-4da1-80a0-0b04f86ab01e" 
        alt="Custom Icon" 
        style={{ width: '24px', height: '24px' }} // Đảm bảo kích thước hiển thị vừa vặn
      /></span>
          <div>
            <div className="navbar__logo-name">Taxi Tây Ninh</div>
            <div className="navbar__logo-sub">Đặt xe 24/7</div>
          </div>
        </a>

        <nav className={`navbar__nav${open ? ' navbar__nav--open' : ''}`}>
          {links.map(l => (
            <a key={l.href} href={l.href} className="navbar__link" onClick={() => setOpen(false)}>
              {l.label}
            </a>
          ))}
          <a href="tel:19001234" className="btn btn-danger btn-sm navbar__cta">
            📞 1900 1234
          </a>
        </nav>

        <button className="navbar__burger" onClick={() => setOpen(!open)} aria-label="Menu">
          <span /><span /><span />
        </button>
      </div>
    </header>
  );
}
